/**
 * Photography Pixel — Cloudflare R2 Media API
 *
 * Scans the R2 bucket, groups media by category folder,
 * and returns clean JSON for the frontend to render.
 *
 * Endpoints:
 *   GET /              — Health check
 *   GET /api/media     — All media grouped by category
 *   GET /api/media?category=ugc — Single category only
 *
 * Caching:
 *   - Edge cache (Cache API): 5 minutes
 *   - Browser cache: 5 minutes via Cache-Control header
 */

// ============================================
// CATEGORY CONFIGURATION
// ============================================
// Each entry maps an R2 folder to a URL slug.
// To add a new category: add a folder in R2 and an entry here.
const CATEGORIES = [
  { folder: 'UGC',          slug: 'ugc',         label: 'UGC' },
  { folder: 'Shooting',     slug: 'shoting',     label: 'Shooting' },
  { folder: 'Stores',       slug: 'stores',      label: 'Stores' },
  { folder: 'Events',       slug: 'events',      label: 'Events' },
  { folder: 'Services',     slug: 'services',    label: 'Services' },
  { folder: 'Photography',  slug: 'photography', label: 'Photography' },
  { folder: 'Gallery',      slug: 'gallery',     label: 'Gallery' },
  { folder: 'Drone',        slug: 'drone',       label: 'Drone' },
  { folder: 'Voice Over',  slug: 'voiceover',   label: 'Voice Over' },
  { folder: 'Media Buyer', slug: 'media-buyer', label: 'Media Buyer' },
  { folder: 'Model',        slug: 'model',       label: 'Model' },
];

const VIDEO_EXTS = ['mp4', 'webm', 'mov', 'avi', 'mkv'];
const AUDIO_EXTS = ['mp3', 'wav', 'ogg', 'm4a', 'flac'];
const IMAGE_EXTS = ['jpg', 'jpeg', 'png', 'webp', 'gif'];
const ALL_EXTS = [...VIDEO_EXTS, ...AUDIO_EXTS, ...IMAGE_EXTS];

const CORS_HEADERS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

// Edge cache duration (seconds)
const CACHE_TTL = 300;

// ============================================
// MAIN ENTRY POINT
// ============================================
export default {
  async fetch(request, env) {
    if (request.method === 'OPTIONS') {
      return new Response(null, { headers: CORS_HEADERS });
    }

    const url = new URL(request.url);
    const path = url.pathname;

    // Health check
    if (path === '/' || path === '/health') {
      return jsonResponse({ status: 'ok', timestamp: Date.now() });
    }

    // Main API endpoint
    if (path === '/api/media') {
      return handleMediaRequest(request, env, url);
    }

    return jsonResponse({ error: 'Not Found' }, 404);
  },
};

// ============================================
// MEDIA REQUEST HANDLER
// ============================================
async function handleMediaRequest(request, env, url) {
  const category = url.searchParams.get('category');
  const cache = caches.default;
  const cacheKey = new Request(url.toString(), { method: 'GET' });

  // Check edge cache first
  const cached = await cache.match(cacheKey);
  if (cached) return cached;

  // Validate configuration
  const publicBase = (env.R2_PUBLIC_URL || '').replace(/\/$/, '');
  if (!publicBase) {
    return jsonResponse({ error: 'R2_PUBLIC_URL not configured' }, 500);
  }

  if (!env.MEDIA_BUCKET) {
    return jsonResponse({ error: 'MEDIA_BUCKET binding not configured' }, 500);
  }

  // Determine which categories to fetch
  const catsToFetch = category
    ? CATEGORIES.filter(c => c.slug === category)
    : CATEGORIES;

  // Fetch all categories in parallel
  const result = {};
  await Promise.all(
    catsToFetch.map(async (cat) => {
      result[cat.slug] = await listCategoryMedia(env, cat, publicBase);
    })
  );

  // Build response with cache headers
  const response = jsonResponse(result, 200, {
    'Cache-Control': `public, max-age=${CACHE_TTL}, s-maxage=${CACHE_TTL * 2}`,
  });

  // Store in edge cache
  const responseToCache = response.clone();
  await cache.put(cacheKey, responseToCache);

  return response;
}

// ============================================
// R2 OBJECT LISTING
// ============================================
async function listCategoryMedia(env, cat, publicBase) {
  const bucket = env.MEDIA_BUCKET;
  const items = [];
  let cursor;

  do {
    const listing = await bucket.list({
      prefix: cat.folder + '/',
      cursor,
      limit: 1000,
      include: ['customMetadata'],
    });

    for (const obj of listing.objects) {
      const ext = obj.key.split('.').pop().toLowerCase();
      if (!ALL_EXTS.includes(ext)) continue;

      // Build public URL — encode each path segment individually
      const encodedKey = obj.key
        .split('/')
        .map(segment => encodeURIComponent(segment))
        .join('/');
      const publicUrl = publicBase + '/' + encodedKey;

      // Derive title from filename (without extension)
      const filename = obj.key.split('/').pop();
      const title = decodeURIComponent(filename.replace(/\.[^/.]+$/, ''));

      // Determine media type
      const type = VIDEO_EXTS.includes(ext) ? 'video'
        : AUDIO_EXTS.includes(ext) ? 'audio'
        : 'image';

      // Use R2 custom metadata if available (set via R2 dashboard or API)
      const meta = obj.customMetadata || {};

      items.push({
        id: cat.slug + '-' + (items.length + 1),
        title: meta.title || title,
        description: meta.description || '',
        video: type === 'video' ? publicUrl : '',
        audio: type === 'audio' ? publicUrl : '',
        thumbnail: type === 'image' ? publicUrl : (meta.thumbnail || ''),
        cover: meta.cover || '',
        category: cat.slug,
        categoryLabel: cat.label,
        featured: meta.featured !== 'false',
        type: type,
        uploaded: obj.uploaded instanceof Date
          ? obj.uploaded.toISOString()
          : new Date(obj.uploaded).toISOString(),
        size: obj.size,
      });
    }

    cursor = listing.truncated ? listing.cursor : undefined;
  } while (cursor);

  // Sort by upload date — newest first
  items.sort((a, b) => new Date(b.uploaded) - new Date(a.uploaded));

  return items;
}

// ============================================
// HELPERS
// ============================================
function jsonResponse(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...CORS_HEADERS,
      ...extraHeaders,
    },
  });
}

export async function onRequestGet(context) {
  return new Response(JSON.stringify({ status: 'ok' }), {
    headers: {
      'Content-Type': 'application/json',
    },
  });
}

